  "inlineSchema": "// ============================================================\n// Prisma Schema — Event Place (MongoDB)\n// Auth custom (sans Better Auth)\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"mongodb\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// AUTH — Custom\n// ============================================================\n\nmodel User {\n  id        String   @id @default(auto()) @map(\"_id\") @db.ObjectId\n  firstName String\n  lastName  String\n  email     String   @unique\n  npi       String   @unique\n  cip       String\n  password  String\n  image     String?\n  role      UserRole @default(ORGANIZER)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relations\n  passwordResetTokens PasswordResetToken[]\n  events              Event[]              @relation(\"OrganizerEvents\")\n}\n\n// Tokens de réinitialisation de mot de passe\nmodel PasswordResetToken {\n  id        String   @id @default(auto()) @map(\"_id\") @db.ObjectId\n  token     String   @unique\n  expiresAt DateTime\n  used      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  userId String @db.ObjectId\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\n// ============================================================\n// DOMAINE — Event Place\n// ============================================================\n\nmodel Event {\n  id          String      @id @default(auto()) @map(\"_id\") @db.ObjectId\n  title       String\n  description String\n  status      EventStatus @default(DRAFT)\n\n  // Relations de classification\n  categoryId String   @db.ObjectId\n  category   Category @relation(fields: [categoryId], references: [id])\n\n  tagIds String[] @db.ObjectId\n  tags   Tag[]    @relation(fields: [tagIds], references: [id])\n\n  // Date & heure\n  dateStart DateTime\n  timeStart String?\n  dateEnd   DateTime?\n  timeEnd   String?\n  multiDay  Boolean   @default(false)\n\n  // Lieu\n  isOnline  Boolean @default(false)\n  onlineUrl String?\n  venue     String?\n  address   String?\n  city      String?\n  capacity  Int?\n\n  // Médias\n  coverImage String\n  gallery    String[]\n\n  // Billetterie\n  isFree    Boolean   @default(false)\n  saleStart DateTime?\n  saleEnd   DateTime?\n\n  // Options\n  isPublic             Boolean @default(true)\n  requiresRegistration Boolean @default(false)\n  showCapacity         Boolean @default(false)\n  allowRefunds         Boolean @default(false)\n  ageRestriction       String?\n  contactEmail         String?\n  website              String?\n  rating               Float?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  organizerId String @db.ObjectId\n  organizer   User   @relation(\"OrganizerEvents\", fields: [organizerId], references: [id])\n\n  tickets  Ticket[]\n  bookings Booking[]\n}\n\n// Nouveau modèle Catégorie (Relation One-to-Many)\nmodel Category {\n  id          String  @id @default(auto()) @map(\"_id\") @db.ObjectId\n  name        String  @unique\n  slug        String  @unique\n  description String?\n  icon        String? // Optionnel : pour l'affichage UI\n\n  events Event[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// Nouveau modèle Tag (Relation Many-to-Many)\nmodel Tag {\n  id   String @id @default(auto()) @map(\"_id\") @db.ObjectId\n  name String @unique\n  slug String @unique\n\n  eventIds String[] @db.ObjectId\n  events   Event[]  @relation(fields: [eventIds], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Ticket {\n  id          String   @id @default(auto()) @map(\"_id\") @db.ObjectId\n  name        String\n  description String?\n  price       Int\n  quantity    Int\n  sold        Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  eventId      String        @db.ObjectId\n  event        Event         @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  bookingItems BookingItem[]\n}\n\nmodel Booking {\n  id          String        @id @default(auto()) @map(\"_id\") @db.ObjectId\n  reference   String        @unique // Ex: \"EP-2025-XXXXX\"\n  userName    String\n  userEmail   String\n  userPhone   String\n  status      BookingStatus @default(PENDING)\n  totalAmount Float\n  paidAt      DateTime?\n  createdAt   DateTime      @default(now())\n  updatedAt   DateTime      @updatedAt\n\n  eventId String        @db.ObjectId\n  event   Event         @relation(fields: [eventId], references: [id])\n  items   BookingItem[]\n}\n\nmodel BookingItem {\n  id       String @id @default(auto()) @map(\"_id\") @db.ObjectId\n  quantity Int\n  price    Float // snapshot du prix au moment de l'achat\n\n  bookingId String  @db.ObjectId\n  booking   Booking @relation(fields: [bookingId], references: [id], onDelete: Cascade)\n  ticketId  String  @db.ObjectId\n  ticket    Ticket  @relation(fields: [ticketId], references: [id])\n}\n\n// ============================================================\n// ENUMS\n// ============================================================\n\nenum UserRole {\n  ORGANIZER // Peut créer des événements\n  ADMIN // Administration de la plateforme\n}\n\nenum EventStatus {\n  DRAFT // En cours de création\n  PENDING // En attente de validation\n  PUBLISHED // Publié et visible\n  CANCELLED // Annulé\n  COMPLETED // Terminé\n}\n\nenum BookingStatus {\n  PENDING // En attente de paiement\n  CONFIRMED // Paiement confirmé\n  CANCELLED // Annulé\n  REFUNDED // Remboursé\n}\n",
